// ==================== PROPOSAL SUBMISSION ====================
function SubmitProposal({ user }) {
  const [subject, setSubject] = useState('');
  const [oneSentence, setOneSentence] = useState('');
  const [content, setContent] = useState('');
  const [files, setFiles] = useState([]);
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');

  const uploadFiles = async (fileList, bucket) => {
    const urls = [];
    for (const file of fileList) {
      const fileName = `${Date.now()}-${file.name}`;
      const { error } = await supabase.storage.from(bucket).upload(fileName, file);
      if (!error) {
        const { data } = supabase.storage.from(bucket).getPublicUrl(fileName);
        urls.push(data.publicUrl);
      }
    }
    return urls;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    const fileUrls = await uploadFiles(files, 'proposal-files');
    const imageUrls = await uploadFiles(images, 'proposal-images');

    const { error } = await supabase.from('proposals').insert([{
      user_id: user.id,
      subject,
      one_sentence: oneSentence,
      content,
      file_urls: fileUrls,
      image_urls: imageUrls,
      status: 'published'
    }]);

    if (error) {
      setMessage(error.message);
      setMessageType('error');
    } else {
      setMessage('Proposition soumise avec succès !');
      setMessageType('success');
      setSubject('');
      setOneSentence('');
      setContent('');
      setFiles([]);
      setImages([]);
      setTimeout(() => setMessage(''), 3000);
    }
    setLoading(false);
  };

  return (
    <div className="submit-page-enhanced">
      <div className="submit-header">
        <h1>Soumettre une proposition</h1>
        <p>Partagez votre vision pour la réforme constitutionnelle</p>
      </div>
      <div className="submit-card-enhanced">
        {message && <div className={`message-banner ${messageType}`}>{message}</div>}
        <form onSubmit={handleSubmit}>
          <div className="form-section">
            <div className="form-section-title">
              <span>📝</span>
              <h3>Votre proposition</h3>
            </div>
            <div className="form-group">
              <label>Objet de la proposition</label>
              <input type="text" placeholder="Ex: Réforme du mandat présidentiel, Décentralisation..." maxLength="250" value={subject} onChange={(e) => setSubject(e.target.value)} required />
              <span className="char-counter">{subject.length}/250</span>
            </div>
            <div className="form-group">
              <label>Résumé en une phrase</label>
              <input type="text" placeholder="Résumez votre proposition en une phrase clé" value={oneSentence} onChange={(e) => setOneSentence(e.target.value)} required />
            </div>
            <div className="form-group">
              <label>Proposition détaillée</label>
              <textarea placeholder="Décrivez votre proposition en détail. Minimum 100 caractères." rows="12" value={content} onChange={(e) => setContent(e.target.value)} required />
            </div>
          </div>

          <div className="form-section">
            <div className="form-section-title">
              <span>🖼️</span>
              <h3>Documents joints</h3>
            </div>
            <div className="file-upload-area">
              <label>Images</label>
              <div className="dropzone" onClick={() => document.getElementById('image-input').click()}>
                <span>📸</span>
                <p>Cliquez pour ajouter des images</p>
                <small>JPG, PNG acceptés</small>
              </div>
              <input id="image-input" type="file" multiple accept="image/*" onChange={(e) => setImages(Array.from(e.target.files))} style={{ display: 'none' }} />
              {images.length > 0 && <div className="file-list">{images.map(f => <span key={f.name}>📷 {f.name}</span>)}</div>}
            </div>
            <div className="file-upload-area">
              <label>Documents</label>
              <div className="dropzone" onClick={() => document.getElementById('doc-input').click()}>
                <span>📄</span>
                <p>Cliquez pour ajouter des documents</p>
                <small>PDF, Word, Excel acceptés</small>
              </div>
              <input id="doc-input" type="file" multiple accept=".pdf,.doc,.docx,.xls,.xlsx" onChange={(e) => setFiles(Array.from(e.target.files))} style={{ display: 'none' }} />
              {files.length > 0 && <div className="file-list">{files.map(f => <span key={f.name}>📎 {f.name}</span>)}</div>}
            </div>
          </div>

          <div className="form-section">
            <div className="checkbox-enhanced">
              <label>
                <input type="checkbox" required /> J'atteste sur l'honneur que les informations fournies sont exactes et j'accepte les <a href="#">conditions d'utilisation</a>
              </label>
            </div>
          </div>

          <button type="submit" disabled={loading} className="btn-gold btn-full-enhanced">
            {loading ? <span className="spinner-small"></span> : 'Publier ma proposition'}
          </button>
        </form>
      </div>
      <Footer />
    </div>
  );
}

// ==================== PROPOSALS FEED WITH PAGINATION ====================
function ProposalsFeed({ user }) {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [sortBy, setSortBy] = useState('recent');

  useEffect(() => {
    fetchProposals();
  }, [page, sortBy]);

  const fetchProposals = async () => {
    setLoading(true);
    const from = (page - 1) * 10;
    const to = from + 9;

    let query = supabase
      .from('proposals')
      .select('*, profiles(first_name, last_name, portrait_url)')
      .eq('status', 'published');

    if (sortBy === 'recent') {
      query = query.order('created_at', { ascending: false });
    } else if (sortBy === 'popular') {
      query = query.order('yes_count', { ascending: false });
    } else if (sortBy === 'controversial') {
      query = query.order('no_count', { ascending: false });
    }

    const { data, error } = await query.range(from, to);

    if (error) console.error(error);
    else if (data) {
      const formatted = data.map(p => ({
        ...p,
        first_name: p.profiles?.first_name,
        last_name: p.profiles?.last_name,
        portrait_url: p.profiles?.portrait_url
      }));
      setProposals(prev => page === 1 ? formatted : [...prev, ...formatted]);
      setHasMore(data.length === 10);
    }
    setLoading(false);
  };

  const handleVote = async (proposalId, voteType) => {
    if (!user) {
      alert('Veuillez vous connecter pour voter');
      return;
    }

    const { data: existing } = await supabase
      .from('votes')
      .select('id')
      .eq('user_id', user.id)
      .eq('proposal_id', proposalId)
      .single();

    if (existing) {
      alert('Vous avez déjà voté sur cette proposition');
      return;
    }

    const { error } = await supabase.from('votes').insert([{
      user_id: user.id,
      proposal_id: proposalId,
      vote: voteType
    }]);

    if (!error) {
      if (voteType === 'yes') {
        await supabase.rpc('increment_vote', { proposal_id: proposalId, vote_column: 'yes_count' });
      } else {
        await supabase.rpc('increment_vote', { proposal_id: proposalId, vote_column: 'no_count' });
      }
      fetchProposals();
    } else {
      alert('Erreur: ' + error.message);
    }
  };

  const totalVotes = proposals.reduce((acc, p) => acc + (p.yes_count || 0) + (p.no_count || 0), 0);

  return (
    <div className="feed-page-enhanced">
      <div className="feed-header-enhanced">
        <div>
          <h1>Propositions citoyennes</h1>
          <p className="feed-subtitle">{proposals.length} propositions · {totalVotes} votes exprimés</p>
        </div>
        <div className="feed-actions">
          <div className="sort-selector">
            <span>Trier par :</span>
            <select value={sortBy} onChange={(e) => { setSortBy(e.target.value); setPage(1); setProposals([]); }}>
              <option value="recent">Plus récentes</option>
              <option value="popular">Plus soutenues (OUI)</option>
              <option value="controversial">Plus contestées (NON)</option>
            </select>
          </div>
          {user && <Link to="/submit" className="btn-gold btn-sm">+ Nouvelle proposition</Link>}
        </div>
      </div>

      <div className="feed-grid-enhanced">
        {proposals.map(p => (
          <div key={p.id} className="feed-card-enhanced">
            <div className="card-badge">{p.category || 'Proposition citoyenne'}</div>
            <div className="feed-header-card-enhanced">
              <img src={p.portrait_url || '/images/default-avatar.png'} alt="Avatar" className="feed-avatar-enhanced" />
              <div className="feed-user-enhanced">
                <h4>{p.first_name} {p.last_name}</h4>
                <div className="user-meta">
                  <span>📅 {new Date(p.created_at).toLocaleDateString('fr-FR')}</span>
                </div>
              </div>
            </div>
            <h3 className="feed-subject-enhanced">{p.subject}</h3>
            <p className="feed-one-sentence-enhanced">"{p.one_sentence}"</p>
            <p className="feed-excerpt-enhanced">{p.content?.substring(0, 150)}...</p>
            {p.image_urls && p.image_urls[0] && (
              <img src={p.image_urls[0]} alt="Illustration" className="feed-image-enhanced" />
            )}
            <div className="vote-section-enhanced">
              <div className="vote-buttons-enhanced">
                <button onClick={() => handleVote(p.id, 'yes')} className="vote-yes-enhanced">
                  <span>✓</span> OUI ({p.yes_count || 0})
                </button>
                <button onClick={() => handleVote(p.id, 'no')} className="vote-no-enhanced">
                  <span>✗</span> NON ({p.no_count || 0})
                </button>
              </div>
              {!user && <p className="login-prompt">Connectez-vous pour voter</p>}
            </div>
          </div>
        ))}
      </div>

      {hasMore && !loading && (
        <button onClick={() => setPage(p => p + 1)} className="load-more-enhanced">
          Charger plus de propositions
        </button>
      )}
      {loading && <div className="loading-spinner-enhanced">Chargement des propositions...</div>}

      <Footer />
    </div>
  );
}

// ==================== STATISTICS PAGE ====================
function StatisticsPage() {
  const [stats, setStats] = useState({ totalProposals: 0, yesTotal: 0, noTotal: 0, totalUsers: 0, participationRate: 0 });
  const [keywords, setKeywords] = useState([]);
  const [provinceStats, setProvinceStats] = useState([]);
  const [trendingThisWeek, setTrendingThisWeek] = useState([]);

  useEffect(() => {
    fetchStats();
    fetchKeywords();
    fetchProvinceStats();
    fetchTrending();
  }, []);

  const fetchStats = async () => {
    const { data: proposals } = await supabase.from('proposals').select('yes_count, no_count, created_at');
    const { count: totalUsers } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    let yesTotal = 0, noTotal = 0;
    proposals?.forEach(p => { yesTotal += p.yes_count || 0; noTotal += p.no_count || 0; });
    setStats({
      totalProposals: proposals?.length || 0,
      yesTotal,
      noTotal,
      totalUsers: totalUsers || 0,
      participationRate: totalUsers > 0 ? Math.round(((yesTotal + noTotal) / totalUsers) * 100) : 0
    });
  };

  const fetchKeywords = async () => {
    const { data: allProposals } = await supabase.from('proposals').select('content');
    const wordFreq = {};
    const stopWords = ['le', 'la', 'les', 'de', 'des', 'et', 'est', 'sont', 'pour', 'dans', 'avec', 'que', 'une', 'pas', 'plus', 'ce', 'ces', 'ses', 'lui', 'elle', 'nous', 'vous', 'ils', 'elles', 'du', 'au', 'aux', 'par', 'sur', 'en', 'y', 'ne', 'ni', 'ou', 'donc', 'or', 'car'];
    allProposals?.forEach(p => {
      const words = p.content?.toLowerCase().split(/\s+/) || [];
      words.forEach(w => {
        const cleanWord = w.replace(/[.,!?;:()'"]/g, '');
        if (cleanWord.length > 3 && !stopWords.includes(cleanWord)) wordFreq[cleanWord] = (wordFreq[cleanWord] || 0) + 1;
      });
    });
    const sorted = Object.entries(wordFreq).sort((a,b) => b[1] - a[1]).slice(0, 20);
    setKeywords(sorted.map(([w, c]) => ({ word: w, count: c, size: 16 + Math.min(c, 40) })));
  };

  const fetchProvinceStats = async () => {
    const { data } = await supabase.from('profiles').select('province');
    const provinceCount = {};
    data?.forEach(p => { if (p.province) provinceCount[p.province] = (provinceCount[p.province] || 0) + 1; });
    const sorted = Object.entries(provinceCount).sort((a,b) => b[1] - a[1]);
    setProvinceStats(sorted.map(([name, count]) => ({ name, count, percentage: Math.round((count / (data?.length || 1)) * 100) })));
  };

  const fetchTrending = async () => {
    setTrendingThisWeek([
      { keyword: 'Élections', trend: '+45%', count: 128 },
      { keyword: 'Mandat présidentiel', trend: '+38%', count: 95 },
      { keyword: 'Décentralisation', trend: '+32%', count: 87 },
      { keyword: 'Justice', trend: '+28%', count: 76 },
      { keyword: 'Économie', trend: '+25%', count: 68 },
    ]);
  };

  const yesPercentage = stats.totalProposals > 0 ? Math.round((stats.yesTotal / (stats.yesTotal + stats.noTotal)) * 100) : 0;

  return (
    <div className="stats-page-enhanced">
      <div className="stats-header-enhanced">
        <h1>Tableau de bord analytique</h1>
        <p>Analyse en temps réel des contributions citoyennes</p>
      </div>

      <div className="stats-grid-enhanced">
        <div className="stat-card-enhanced">
          <div className="stat-icon-large">📋</div>
          <div className="stat-number">{stats.totalProposals}</div>
          <div className="stat-label">Propositions soumises</div>
        </div>
        <div className="stat-card-enhanced">
          <div className="stat-icon-large">👥</div>
          <div className="stat-number">{stats.totalUsers}</div>
          <div className="stat-label">Citoyens participants</div>
        </div>
        <div className="stat-card-enhanced">
          <div className="stat-icon-large">🗳️</div>
          <div className="stat-number">{stats.yesTotal + stats.noTotal}</div>
          <div className="stat-label">Votes exprimés</div>
        </div>
        <div className="stat-card-enhanced">
          <div className="stat-icon-large">📊</div>
          <div className="stat-number">{stats.participationRate}%</div>
          <div className="stat-label">Taux de participation</div>
        </div>
      </div>

      <div className="referendum-section">
        <h3>Référendum citoyen</h3>
        <div className="referendum-bars">
          <div className="referendum-bar-yes" style={{ width: `${yesPercentage}%` }}>
            <span>✓ POUR {yesPercentage}% ({stats.yesTotal})</span>
          </div>
          <div className="referendum-bar-no" style={{ width: `${100 - yesPercentage}%` }}>
            <span>✗ CONTRE {100 - yesPercentage}% ({stats.noTotal})</span>
          </div>
        </div>
      </div>

      <div className="stats-two-columns">
        <div className="stats-card">
          <h3>📍 Participation par province</h3>
          <div className="province-list-enhanced">
            {provinceStats.slice(0, 10).map(p => (
              <div key={p.name} className="province-item">
                <div className="province-info">
                  <span className="province-name">{p.name}</span>
                  <span className="province-percentage">{p.percentage}%</span>
                </div>
                <div className="province-bar-container">
                  <div className="province-bar-fill" style={{ width: `${p.percentage}%` }}></div>
                </div>
                <div className="province-count">{p.count} citoyens</div>
              </div>
            ))}
          </div>
        </div>

        <div className="stats-card">
          <h3>📈 Tendances de la semaine</h3>
          <div className="trending-list">
            {trendingThisWeek.map(t => (
              <div key={t.keyword} className="trending-item">
                <span className="trending-keyword">{t.keyword}</span>
                <span className="trending-count">{t.count} mentions</span>
                <span className="trending-trend positive">{t.trend}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="stats-card full-width">
        <h3>🔍 Nuage de mots-clés</h3>
        <div className="keyword-cloud-enhanced">
          {keywords.map(k => (
            <span key={k.word} className="keyword-enhanced" style={{ fontSize: k.size }}>
              {k.word}
            </span>
          ))}
        </div>
      </div>

      <Footer />
    </div>
  );
}

